-- create "household_currencies" table
CREATE TABLE "household_currencies" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY (START WITH 73014444032), "create_time" timestamptz NOT NULL, "update_time" timestamptz NOT NULL, "important" boolean NOT NULL DEFAULT false, "currency_id" bigint NOT NULL, "household_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "household_currencies_currencies_household_currencies" FOREIGN KEY ("currency_id") REFERENCES "currencies" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "household_currencies_households_household_currencies" FOREIGN KEY ("household_id") REFERENCES "households" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
-- create index "householdcurrency_household_id_currency_id" to table: "household_currencies"
CREATE UNIQUE INDEX "householdcurrency_household_id_currency_id" ON "household_currencies" ("household_id", "currency_id");
-- create "household_rates" table
CREATE TABLE "household_rates" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY (START WITH 77309411328), "create_time" timestamptz NOT NULL, "update_time" timestamptz NOT NULL, "rate" numeric(36,18) NOT NULL, "from_currency_id" bigint NOT NULL, "to_currency_id" bigint NOT NULL, "household_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "household_rates_currencies_household_rates_from" FOREIGN KEY ("from_currency_id") REFERENCES "currencies" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "household_rates_currencies_household_rates_to" FOREIGN KEY ("to_currency_id") REFERENCES "currencies" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "household_rates_households_household_rates" FOREIGN KEY ("household_id") REFERENCES "households" ("id") ON UPDATE NO ACTION ON DELETE CASCADE);
-- create index "householdrate_household_id_from_currency_id_to_currency_id" to table: "household_rates"
CREATE UNIQUE INDEX "householdrate_household_id_from_currency_id_to_currency_id" ON "household_rates" ("household_id", "from_currency_id", "to_currency_id");
-- modify "user_households" table
ALTER TABLE "user_households" ADD COLUMN "default_currency_id" bigint NULL, ADD CONSTRAINT "user_households_household_currencies_default_currency" FOREIGN KEY ("default_currency_id") REFERENCES "household_currencies" ("id") ON UPDATE NO ACTION ON DELETE SET NULL;
